SELECT * 
FROM state_scores 
WHERE state_id = 1;

SELECT COUNT(*) 
FROM user_role_mapping 
WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT MAX(participation_rate) AS max_participation_rate
FROM state_scores
WHERE academic_year = 2020;

SELECT state_name
FROM state_scores
WHERE math_score > (SELECT AVG(math_score) FROM state_scores);

SELECT state_name
FROM state_scores
ORDER BY math_score DESC;

SELECT s.subject_name, CAST(na.english_score AS REAL) as avg_english_score
FROM national_averages na
CROSS JOIN subjects s;

SELECT state_name, participation_rate, english_score, math_score
FROM state_scores
WHERE composite_score >= 200;

SELECT state_name, english_score, composite_score
FROM state_scores
WHERE academic_year = 2018 AND participation_rate > 80;
